relativeUrl.value:
@concat(
    'https://app.leadconduit.com/events?start=',
    concat(dataset().Date, 'T', dataset().StartTime, 'Z'),
    '&end=',
    concat(
        formatDateTime(
            addSeconds(
                concat(dataset().Date, 'T', dataset().StartTime),
                299
            ),
            'yyyy-MM-ddTHH:mm:ss'
        ),
        'Z'
    ),
    '&sort=asc&limit=1000&after_id=692ce0588c641aee962cfbbb'
)
